import subprocess
import os
import sys

def generate_requirements_txt():
    """Generate requirements.txt with hashes for package integrity."""
    try:
        subprocess.run(['pip', 'freeze', '--require-hashes'], check=True, stdout=open('requirements.txt', 'w'))
        print("requirements.txt generated successfully with hashes.")
    except subprocess.CalledProcessError as e:
        print(f"Error generating requirements.txt: {e}")
        sys.exit(1)

def update_requirements_txt():
    """Update requirements.txt with the latest package versions and hashes."""
    try:
        subprocess.run(['pip', 'install', '--upgrade', '-r', 'requirements.txt'], check=True)
        generate_requirements_txt()
    except subprocess.CalledProcessError as e:
        print(f"Error updating requirements.txt: {e}")
        sys.exit(1)

def generate_poetry_lock():
    """Generate or update poetry.lock file for consistent dependencies."""
    try:
        subprocess.run(['poetry', 'update'], check=True)
        print("poetry.lock updated successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Error updating poetry.lock: {e}")
        sys.exit(1)

def install_dependencies():
    """Install dependencies from requirements.txt or poetry.lock."""
    if os.path.exists('requirements.txt'):
        try:
            subprocess.run(['pip', 'install', '-r', 'requirements.txt'], check=True)
            print("Dependencies installed from requirements.txt.")
        except subprocess.CalledProcessError as e:
            print(f"Error installing dependencies: {e}")
            sys.exit(1)
    elif os.path.exists('pyproject.toml'):
        try:
            subprocess.run(['poetry', 'install'], check=True)
            print("Dependencies installed from poetry.lock.")
        except subprocess.CalledProcessError as e:
            print(f"Error installing dependencies: {e}")
            sys.exit(1)
    else:
        print("No requirements.txt or pyproject.toml found.")

if __name__ == "__main__":
    action = input("Choose an action (generate, update, install): ").strip().lower()
    if action == 'generate':
        generate_requirements_txt()
    elif action == 'update':
        update_requirements_txt()
    elif action == 'install':
        install_dependencies()
    else:
        print("Invalid action. Please choose 'generate', 'update', or 'install'.")